from argparse import ArgumentParser
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(bootstrap_servers, topic_name):
    admin = KafkaAdminClient(bootstrap_servers=bootstrap_servers)
    new_topic = NewTopic(name=topic_name, num_partitions=1, replication_factor=3)
    try:
        admin.create_topics([new_topic])
        print(f"Topic {topic_name} created successfully")
    except Exception as e:
        print(f"Failed to create topic due to error: {str(e)}")
        
def parse_arguments():
    parser = ArgumentParser()
    parser.add_argument("-b", "--bootstrap_servers", dest="bootstrap_servers", required=True, help="Bootstrap servers address")
    parser.add_argument("-t", "--topic_name", dest="topic_name", required=True, help="Topic name to create")
    return vars(parser.parse_args())
        
def main():
    args = parse_arguments()
    create_topic(args['bootstrap_servers'], args['topic_name'])
    
if __name__ == "__main__":
    main()